mapper.select:
SELECT 
  FROM er.tn_er_cntry_pair_co2 p
 WHERE p.er_id   = #{erId}
   AND p.pair_sn = #{pairSn}
   AND NOW() BETWEEN p.use_bgng_dt AND p.use_end_dt

SELECT COALESCE(MAX(pair_sn), 0) + 1
  FROM er.tn_er_cntry_pair_co2
 WHERE er_id = #{erId}

SELECT CASE WHEN COUNT(*) > 0 THEN TRUE ELSE FALSE END
  FROM er.tn_er_cntry_pair_co2
 WHERE er_id           = #{erId}
   AND dprtr_cntry_cd  = #{dprtrCntryCd}
   AND arvl_cntry_cd   = #{arvlCntryCd}
   AND fuel_type_cd    = #{fuelTypeCd}
   AND pair_sn        != #{excludeSn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

mapper.update:
UPDATE er.tn_er_cntry_pair_co2
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE er_id   = #{erId}
   AND pair_sn = #{pairSn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
